from leann.api import LeannBuilder, LeannSearcher
from pathlib import Path

def convert_cli_args_to_api_config(
    args_list: List[str],
    command_type: str = "build"
) -> Dict[str, Any]:
    """Convert CLI arguments to API configuration dictionary.

    Args:
        args_list: List of command line arguments
        command_type: Type of command ('build' or 'search')

    Returns:
        Dictionary containing API configuration extracted from CLI arguments
    """
    # Create CLI parser instance
    cli_parser = LeannCLI()

    # Parse the arguments using leann's CLI parser
    parsed_args = cli_parser.parse_args(args_list)

    # Base configuration structure
    config: Dict[str, Any] = {
        "command": command_type,
    }

    # Common parameters that apply to both commands
    common_params = [
        "index_path", "model_name", "embedding_dim", "chunk_size", 
        "chunk_overlap", "max_tokens", "batch_size", "device", "verbose"
    ]

    # Extract common parameters
    for param in common_params:
        if hasattr(parsed_args, param) and getattr(parsed_args, param) is not None:
            config[param] = getattr(parsed_args, param)

    # Command-specific parameters
    if command_type == "build":
        # Build-specific parameters
        build_params = ["docs_path", "recursive", "file_types", "clean", "force"]
        for param in build_params:
            if hasattr(parsed_args, param) and getattr(parsed_args, param) is not None:
                config[param] = getattr(parsed_args, param)

        # Handle docs_path as Path objects if they exist
        if hasattr(parsed_args, "docs_path") and parsed_args.docs_path:
            if isinstance(parsed_args.docs_path, list):
                config["docs_path"] = [Path(p) for p in parsed_args.docs_path]
            else:
                config["docs_path"] = Path(parsed_args.docs_path)

    elif command_type == "search":
        # Search-specific parameters
        search_params = ["query", "top_k", "threshold", "include_metadata", "output_format"]
        for param in search_params:
            if hasattr(parsed_args, param) and getattr(parsed_args, param) is not None:
                config[param] = getattr(parsed_args, param)

        # Ensure query is properly handled
        if hasattr(parsed_args, "query") and parsed_args.query:
            config["query"] = parsed_args.query

    # Handle index_path as Path object if it exists
    if "index_path" in config and config["index_path"]:
        config["index_path"] = Path(config["index_path"])

    return config

